import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Login = () => {
  const [address, setAddress] = useState('');
  const [network, setNetwork] = useState('1'); // По умолчанию Ethereum
  const [signature, setSignature] = useState('test_signature'); // В реальном приложении тут будет реальная подпись
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState('');

  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!address || !network) {
      setError('Пожалуйста, заполните все поля');
      return;
    }

    try {
      setError('');
      setLoading(true);

      const result = await login(address, parseInt(network), signature);

      setSuccess('Вход выполнен успешно!');

      // Перенаправляем пользователя на страницу профиля
      setTimeout(() => {
        navigate('/profile');
      }, 1500);

    } catch (error) {
      console.error('Ошибка при входе:', error);
      setError(error.response?.data?.detail || 'Ошибка при попытке входа');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container">
      <div className="card" style={{ maxWidth: '500px', margin: '40px auto' }}>
        <h2 style={{ marginBottom: '20px' }}>Вход / Регистрация</h2>

        {error && (
          <div className="alert alert-danger">{error}</div>
        )}

        {success && (
          <div className="alert alert-success">{success}</div>
        )}

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="network" className="form-label">
              Сеть
            </label>
            <select
              id="network"
              className="form-control"
              value={network}
              onChange={(e) => setNetwork(e.target.value)}
              disabled={loading}
            >
              <option value="1">Ethereum</option>
              <option value="3">TON</option>
            </select>
          </div>

          <div className="form-group">
            <label htmlFor="address" className="form-label">
              Адрес кошелька
            </label>
            <input
              type="text"
              id="address"
              className="form-control"
              value={address}
              onChange={(e) => setAddress(e.target.value)}
              placeholder="Введите адрес кошелька (например, 0x...)"
              disabled={loading}
              required
            />
          </div>

          <button
            type="submit"
            className="btn"
            disabled={loading}
            style={{ width: '100%' }}
          >
            {loading ? 'Выполняется вход...' : 'Войти / Зарегистрироваться'}
          </button>
        </form>

        <div style={{ marginTop: '20px', textAlign: 'center' }}>
          <p>
            В этой демо-версии вы можете использовать любой адрес кошелька для входа.
            <br />
            Например: <code>0x123456789abcdef</code> для Ethereum или <code>EQA123456789abcdef</code> для TON.
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
